from libc.math cimport sqrt


cpdef float dot(Vector a, Vector b):
    return a.X * b.X + a.Y * b.Y + a.Z * b.Z

cpdef Vector cross(Vector a, Vector b):
    return Vector(
        a.Y * b.Z - a.Z * b.Y,
        a.Z * b.X - a.X * b.Z,
        a.X * b.Y - a.Y * b.X
    )


cdef class Vector:

    def __init__(Vector self, float x, float y, float z):
        self.X = x
        self.Y = y
        self.Z = z

    def __cinit__(Vector self, float x, float y, float z):
        self.X = x
        self.Y = y
        self.Z = z

    def __str__(Vector self):
        return "Vector <{0}, {1}, {2}>".format(self.X, self.Y, self.Z)

    cpdef Vector copy(Vector self):
        return Vector(self.X, self.Y, self.Z)

    def __neg__(Vector self):
        return Vector(-self.X, -self.Y, -self.Z)

    def __abs__(Vector self):
        return Vector(abs(self.X), abs(self.Y), abs(self.Z))

    def __add__(Vector self, Vector other):
        return Vector(self.X + other.X, self.Y + other.Y, self.Z + other.Z)

    def __mul__(Vector self, float other):
        return Vector(self.X * other, self.Y * other, self.Z * other)

    def __matmul__(Vector self, Vector other):
        return Vector(self.X * other.X, self.Y * other.Y, self.Z * other.Z)

    def __iadd__(Vector self, Vector other):
        self.X += other.X; self.Y += other.Y; self.Z +=other.Z
        return self

    def __sub__(Vector self, Vector other):
        return Vector(self.X - other.X, self.Y - other.Y, self.Z - other.Z)

    def __isub__(Vector self, Vector other):
        self.X -= other.X; self.Y -= other.Y; self.Z -= other.Z
        return self

    cpdef float len(Vector self):
        return sqrt(self.X * self.X + self.Y * self.Y + self.Z * self.Z)

    cpdef float len_squared(Vector self):
        return self.X * self.X + self.Y * self.Y + self.Z * self.Z

    def __truediv__(Vector self, float other):
        return Vector(self.X / other, self.Y / other, self.Z / other)

    def __itruediv__(Vector self, float other):
        self.X /= other; self.Y /= other; self.Z /= other
        return self

    cpdef Vector clip(Vector self, float _min, float _max):

        if _min > self.X: self.X = _min
        elif _max < self.X: self.X = _max

        if _min > self.Y: self.Y = _min
        elif _max < self.Y: self.Y = _max

        if _min > self.Z: self.Z = _min
        elif _max < self.Z: self.Z = _max

        return self

    cdef Vector normalize(Vector self):
        cdef float len = self.len()
        self.X /= len; self.Y /= len; self.Z /= len
        return self

    cpdef Vector normalized(Vector self):
        return self.copy().normalize()


cdef class Ray:

    def __init__(Ray self, Vector origin, Vector direction):
        self.Origin = origin
        self.Direction = direction

    def __cinit_(Ray self, Vector origin, Vector direction):
        self.Origin = Vector(origin.X, origin.Y, origin.Z)
        self.Direction = Vector(direction.X, direction.Y, direction.Z)
        self.Direction.normalize()

    def __str__(Ray self):
        return "Ray: {" + "Origin: " + str(self.Origin) + ", Direction: " + str(self.Direction) + "}"

    cpdef Vector distanced(Ray self, float distance):
        return self.Origin + self.Direction * distance

cdef class Cons:
    cdef object car
    cdef object cdr
    def __cinit__(Cons self, object car, object cdr):
        self.car = car
        self.cdr = cdr
    #enddef
    def __len__(Cons self):
        len_acc(self, 0)
    #enddef    
    def __richcmp__(Cons self, object x, int op):
        if(op == 2 || op == 3):
            int result = cmp_acc(self, <Cons?>x);
            if(op == 2):
                return result;
            else:
                return !result;
            #endif
        else:
            raise(TypeError("Cons does not support ordered comparisons"));
        #endif
    #enddef
#endcdef class Cons

#car and cdr are python functions, just use direct access in C
def object car(Cons ls):
    if(ls is not None):
        return ls.car
    else
        return None
    #endif
#enddef
def object cdr(Cons ls):
    if(ls is not None)
        return ls.cdr
    else
        return None
    #endif
#enddef
cpdef object pop(Cons ls):
    if(ls is not None):
        object ret = ls.car;
        ls = ls.cdr;
        return ret;
    else:
        return None;
    #endif
#endcpdef
cpdef object push(object elt, Cons ls):
    Cons ret = Cons(elt, ls);
    ls = ret;
    return ret;
#endcpdef
#Define recursive functions in C, make python wrappers around them
cdef long len_acc(Cons ls, long acc):
    if(ls.cdr is None):
        return acc
    else:
        return len_acc(ls.cdr,acc+1)
    #endif
#endcdef
cdef int cmp_acc(Cons x, Cons y):
    if(x is not None && y is not None):
        if(x.car == y.car):
            return cmp_acc(x.cdr, y.cdr);
        else
            return 0;
        #endif
    elif(x is None && y is None):
        return 1;
    else:
        return 0;
    #endif
#endcdef    

cdef object nth_acc(Cons l, long n):
    if(l is None):   #need to check this first
        return None
    elif(n == 0)
        return l.car
    else
        return nth(l.cdr, n-1)
    #endif
#endcdef
cdef consp(object obj):
    return isinstance(obj, Cons);
#endcdef

#define in C to make looping efficent
#assume non None value for l
cdef Cons mapcar(object fxn, Cons l):
    Cons ret = Cons(fxn(pop(l)), None);
    Cons *tail = &ret;
    while(consp(l)):
        tail.cdr = fxn(pop(l));
        tail = &tail.cdr
    #endwhile
#endcdef    

#Assumes a non-empty tuple
cdef Cons tuple_to_cons(object tpl):
    Cons ret = Cons(tpl[0], None);
    Cons* tail = &ret; #I'm not totally sure how cython treats pointers
    long n = len(tpl);
    for i from 1 <= i < n:
        tail.cdr = Cons(tpl[i], None);
        tail = &tail.cdr;
    #endfor
    return ret
#endcdef

#make small lists
cdef Cons list1(object a):
    return Cons(a,None);
#endcdef
cdef Cons list2(object a, object b):
    return Cons(a,Cons(b, None));
#endcdef


#since calling it list would shadow the python function
def Cons make_list(*rest):
    if(rest):
        return tuple_to_cons(rest);
    else:
        return None;
    #endif
#enddef
